module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

    reg a_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            a_reg <= 1'b0;
            rise <= 1'b0;
            down <= 1'b0;
        end else begin
            a_reg <= a;
            if (a > a_reg) begin
                rise <= 1'b1;
                down <= 1'b0;
            end else if (a < a_reg) begin
                rise <= 1'b0;
                down <= 1'b1;
            end else begin
                rise <= 1'b0;
                down <= 1'b0;
            end
        end
    end

endmodule
